   272→  const config = await getGoogleConfig();
   273→  if (!config) { res.redirect("/"); return; }
   274→
   275→  const callbackUrl = `${getOrigin(req)}/api/auth/google/callback`;
   276→  const codeVerifier = req.cookies?.g_code_verifier;
   277→  const nonce = req.cookies?.g_nonce;
