import { useEffect, useState } from "react";
import { X, Mail, Eye, EyeOff, ArrowLeft, Key } from "lucide-react";

interface LoginModalProps {
  view: "login" | "register";
  onClose: () => void;
  onSwitchView: (view: "login" | "register") => void;
}

const ClientumLogo = () => (
  <div className="flex justify-center mb-5">
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 48 48" width="44" height="44" fill="none">
      <rect width="48" height="48" rx="10" fill="#E8470A" />
      <rect x="10" y="10" width="12" height="12" rx="2" fill="white" />
      <rect x="26" y="10" width="12" height="12" rx="2" fill="white" />
      <rect x="26" y="26" width="12" height="12" rx="2" fill="white" />
    </svg>
  </div>
);

const GoogleIcon = () => (
  <svg width="18" height="18" viewBox="0 0 18 18" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M17.64 9.205c0-.639-.057-1.252-.164-1.841H9v3.481h4.844a4.14 4.14 0 01-1.796 2.716v2.259h2.908c1.702-1.567 2.684-3.875 2.684-6.615z" fill="#4285F4"/>
    <path d="M9 18c2.43 0 4.467-.806 5.956-2.18l-2.908-2.259c-.806.54-1.837.86-3.048.86-2.344 0-4.328-1.584-5.036-3.711H.957v2.332A8.997 8.997 0 009 18z" fill="#34A853"/>
    <path d="M3.964 10.71A5.41 5.41 0 013.682 9c0-.593.102-1.17.282-1.71V4.958H.957A8.996 8.996 0 000 9c0 1.452.348 2.827.957 4.042l3.007-2.332z" fill="#FBBC05"/>
    <path d="M9 3.58c1.321 0 2.508.454 3.44 1.345l2.582-2.58C13.463.891 11.426 0 9 0A8.997 8.997 0 00.957 4.958L3.964 7.29C4.672 5.163 6.656 3.58 9 3.58z" fill="#EA4335"/>
  </svg>
);

type SubView = "options" | "email-form";

export default function LoginModal({ view, onClose, onSwitchView }: LoginModalProps) {
  const isLogin = view === "login";
  const [subView, setSubView] = useState<SubView>("options");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => { if (e.key === "Escape") onClose(); };
    document.addEventListener("keydown", handleKey);
    document.body.style.overflow = "hidden";
    return () => {
      document.removeEventListener("keydown", handleKey);
      document.body.style.overflow = "";
    };
  }, [onClose]);

  useEffect(() => {
    setSubView("options");
    setError(null);
    setEmail("");
    setPassword("");
  }, [view]);

  const handleGoogle = () => {
    window.location.href = "/api/auth/google";
  };

  const handleEmailSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
      const endpoint = isLogin ? "/api/auth/login-email" : "/api/auth/register";
      const res = await fetch(endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
        credentials: "include",
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || "Error al procesar la solicitud");
        return;
      }
      window.location.href = data.redirectTo || "/dashboard";
    } catch {
      setError("Error de conexión. Intentá de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const switchAndReset = (v: "login" | "register") => {
    setSubView("options");
    setError(null);
    onSwitchView(v);
  };

  return (
    <div
      className="fixed inset-0 z-[9999] flex items-center justify-center p-4"
      style={{ background: "rgba(0,0,0,0.45)", backdropFilter: "blur(3px)" }}
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div
        className="relative w-full max-w-[400px] rounded-2xl shadow-xl overflow-hidden animate-in fade-in zoom-in-95 duration-200"
        style={{ background: "#F5F4F0" }}
      >
        <button
          onClick={onClose}
          className="absolute top-4 right-4 w-7 h-7 rounded-full flex items-center justify-center text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-all z-10"
        >
          <X size={16} />
        </button>

        <div className="px-8 pt-9 pb-7">
          {subView === "options" ? (
            <>
              <ClientumLogo />

              <h2 className="text-[22px] font-bold text-center text-gray-900 mb-7">
                {isLogin ? "Ingresar a Clientum" : "Crear una cuenta"}
              </h2>

              <div className="space-y-2.5">
                <button
                  onClick={handleGoogle}
                  className="w-full flex items-center justify-center gap-3 px-4 py-2.5 rounded-lg border border-gray-300 bg-white text-gray-700 font-medium text-sm hover:bg-gray-50 transition-all"
                >
                  <GoogleIcon />
                  Continuar con Google
                </button>

                <button
                  onClick={() => setSubView("email-form")}
                  className="w-full flex items-center justify-center gap-3 px-4 py-2.5 rounded-lg border border-gray-300 bg-white text-gray-700 font-medium text-sm hover:bg-gray-50 transition-all"
                >
                  <Mail size={17} className="text-gray-500" />
                  Continuar con email
                </button>

                {isLogin && (
                  <button
                    onClick={() => window.location.href = "/api/login"}
                    className="w-full flex items-center justify-center gap-3 px-4 py-2.5 rounded-lg border border-gray-300 bg-white text-gray-700 font-medium text-sm hover:bg-gray-50 transition-all"
                  >
                    <Key size={16} className="text-gray-500" />
                    Usar SSO
                  </button>
                )}

                <button
                  onClick={() => window.location.href = "/api/login"}
                  className="w-full text-center text-sm text-gray-500 hover:text-gray-700 py-1.5 transition-colors"
                >
                  Ver más opciones
                </button>
              </div>

              <div className="mt-6 pt-5 border-t border-gray-300">
                <p className="text-center text-sm text-gray-500">
                  {isLogin ? (
                    <>
                      ¿Nuevo por acá?{" "}
                      <button
                        onClick={() => switchAndReset("register")}
                        className="font-semibold text-[#E8470A] hover:underline transition-all"
                      >
                        Crear cuenta
                      </button>
                    </>
                  ) : (
                    <>
                      ¿Ya tenés cuenta?{" "}
                      <button
                        onClick={() => switchAndReset("login")}
                        className="font-semibold text-[#E8470A] hover:underline transition-all"
                      >
                        Iniciar sesión
                      </button>
                    </>
                  )}
                </p>
              </div>
            </>
          ) : (
            <>
              <button
                onClick={() => { setSubView("options"); setError(null); }}
                className="flex items-center gap-1.5 text-sm text-gray-500 hover:text-gray-700 mb-5 transition-colors"
              >
                <ArrowLeft size={15} />
                Atrás
              </button>

              <ClientumLogo />

              <h2 className="text-[22px] font-bold text-center text-gray-900 mb-6">
                {isLogin ? "Ingresar con email" : "Crear una cuenta"}
              </h2>

              <form onSubmit={handleEmailSubmit} className="space-y-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1.5">
                    Email
                  </label>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                    autoFocus
                    placeholder="tu@email.com"
                    className="w-full px-3 py-2.5 rounded-lg border border-gray-300 bg-white text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#E8470A]/30 focus:border-[#E8470A] transition-all"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1.5">
                    Contraseña
                  </label>
                  <div className="relative">
                    <input
                      type={showPassword ? "text" : "password"}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                      minLength={6}
                      placeholder="Mínimo 6 caracteres"
                      className="w-full px-3 py-2.5 pr-10 rounded-lg border border-gray-300 bg-white text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#E8470A]/30 focus:border-[#E8470A] transition-all"
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition-colors"
                    >
                      {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>

                {error && (
                  <p className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-lg px-3 py-2">
                    {error}
                  </p>
                )}

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full py-2.5 rounded-lg text-white font-semibold text-sm transition-all mt-1 disabled:opacity-60"
                  style={{ background: loading ? "#ccc" : "#E8470A" }}
                >
                  {loading ? "Procesando..." : isLogin ? "Ingresar" : "Crear cuenta"}
                </button>
              </form>

              <div className="mt-5 pt-4 border-t border-gray-300">
                <p className="text-center text-sm text-gray-500">
                  {isLogin ? (
                    <>
                      ¿Nuevo por acá?{" "}
                      <button
                        onClick={() => switchAndReset("register")}
                        className="font-semibold text-[#E8470A] hover:underline transition-all"
                      >
                        Crear cuenta
                      </button>
                    </>
                  ) : (
                    <>
                      ¿Ya tenés cuenta?{" "}
                      <button
                        onClick={() => switchAndReset("login")}
                        className="font-semibold text-[#E8470A] hover:underline transition-all"
                      >
                        Iniciar sesión
                      </button>
                    </>
                  )}
                </p>
              </div>
            </>
          )}
        </div>

        <div className="px-8 pb-5">
          <p className="text-center text-xs text-gray-400 leading-relaxed">
            Al continuar aceptás nuestros{" "}
            <a href="#" className="underline hover:text-gray-600">Términos de servicio</a>
            {" "}y{" "}
            <a href="#" className="underline hover:text-gray-600">Política de privacidad</a>.
          </p>
        </div>
      </div>
    </div>
  );
}

