import { useState, useEffect } from "react";
import { useLocation } from "wouter";
import { Eye, EyeOff, CheckCircle2, XCircle } from "lucide-react";

const ClientumLogo = () => (
  <div className="flex justify-center mb-5">
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 48 48" width="44" height="44" fill="none">
      <rect width="48" height="48" rx="10" fill="#E8470A" />
      <rect x="10" y="10" width="12" height="12" rx="2" fill="white" />
      <rect x="26" y="10" width="12" height="12" rx="2" fill="white" />
      <rect x="26" y="26" width="12" height="12" rx="2" fill="white" />
    </svg>
  </div>
);

export default function ResetPassword() {
  const [, setLocation] = useLocation();
  const [token, setToken] = useState<string | null>(null);
  const [password, setPassword] = useState("");
  const [confirm, setConfirm] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const t = params.get("token");
    if (!t) setError("El enlace es inválido o ya expiró.");
    else setToken(t);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 6) {
      setError("La contraseña debe tener al menos 6 caracteres.");
      return;
    }
    if (password !== confirm) {
      setError("Las contraseñas no coinciden.");
      return;
    }
    setError(null);
    setLoading(true);
    try {
      const res = await fetch("/api/auth/reset-password", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ token, password }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || "Error al restablecer la contraseña.");
        return;
      }
      setDone(true);
    } catch {
      setError("Error de conexión. Intentá de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className="min-h-screen flex items-center justify-center p-4"
      style={{ background: "#f4f4f5" }}
    >
      <div
        className="w-full max-w-[400px] rounded-2xl shadow-xl overflow-hidden"
        style={{ background: "#F5F4F0" }}
      >
        <div className="px-8 pt-9 pb-7">
          <ClientumLogo />

          {done ? (
            <div className="text-center">
              <div className="flex justify-center mb-4">
                <CheckCircle2 size={48} className="text-green-500" />
              </div>
              <h2 className="text-[22px] font-bold text-gray-900 mb-3">¡Contraseña actualizada!</h2>
              <p className="text-sm text-gray-500 mb-6">
                Tu contraseña fue restablecida con éxito. Ya podés ingresar con tu nueva contraseña.
              </p>
              <button
                onClick={() => setLocation("/")}
                className="w-full py-2.5 rounded-lg text-white font-semibold text-sm"
                style={{ background: "#E8470A" }}
              >
                Volver al inicio
              </button>
            </div>
          ) : !token ? (
            <div className="text-center">
              <div className="flex justify-center mb-4">
                <XCircle size={48} className="text-red-400" />
              </div>
              <h2 className="text-[22px] font-bold text-gray-900 mb-3">Enlace inválido</h2>
              <p className="text-sm text-gray-500 mb-6">
                Este enlace es inválido o ya expiró. Solicitá un nuevo enlace de recuperación.
              </p>
              <button
                onClick={() => setLocation("/")}
                className="w-full py-2.5 rounded-lg text-white font-semibold text-sm"
                style={{ background: "#E8470A" }}
              >
                Volver al inicio
              </button>
            </div>
          ) : (
            <>
              <h2 className="text-[22px] font-bold text-center text-gray-900 mb-2">
                Nueva contraseña
              </h2>
              <p className="text-sm text-center text-gray-500 mb-6">
                Ingresá tu nueva contraseña para Clientum.
              </p>

              <form onSubmit={handleSubmit} className="space-y-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1.5">
                    Nueva contraseña
                  </label>
                  <div className="relative">
                    <input
                      type={showPw ? "text" : "password"}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                      minLength={6}
                      autoFocus
                      placeholder="Mínimo 6 caracteres"
                      className="w-full px-3 py-2.5 pr-10 rounded-lg border border-gray-300 bg-white text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#E8470A]/30 focus:border-[#E8470A] transition-all"
                    />
                    <button
                      type="button"
                      onClick={() => setShowPw(!showPw)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition-colors"
                    >
                      {showPw ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1.5">
                    Repetir contraseña
                  </label>
                  <div className="relative">
                    <input
                      type={showConfirm ? "text" : "password"}
                      value={confirm}
                      onChange={(e) => setConfirm(e.target.value)}
                      required
                      placeholder="Repetí la contraseña"
                      className="w-full px-3 py-2.5 pr-10 rounded-lg border border-gray-300 bg-white text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#E8470A]/30 focus:border-[#E8470A] transition-all"
                    />
                    <button
                      type="button"
                      onClick={() => setShowConfirm(!showConfirm)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition-colors"
                    >
                      {showConfirm ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>

                {error && (
                  <p className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-lg px-3 py-2">
                    {error}
                  </p>
                )}

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full py-2.5 rounded-lg text-white font-semibold text-sm transition-all mt-1 disabled:opacity-60"
                  style={{ background: loading ? "#ccc" : "#E8470A" }}
                >
                  {loading ? "Guardando..." : "Guardar nueva contraseña"}
                </button>
              </form>
            </>
          )}
        </div>

        <div className="px-8 pb-5 border-t border-gray-200">
          <p className="text-center text-xs text-gray-400 leading-relaxed mt-4">
            © {new Date().getFullYear()} Clientum · IA para PyMEs
          </p>
        </div>
      </div>
    </div>
  );
}

